    B --> E["install 事件<br>预缓存资源"]
    B --> F["activate 事件<br>清理旧缓存"]
    B --> G["fetch 事件<br>请求拦截与响应"]
    B --> H["push 事件<br>推送通知"]
    B --> I["sync 事件<br>后台同步"]
