function flatMap(arr, callback, thisArg) {
  return arr.reduce((acc, item, index) => {
    const mapped = callback.call(thisArg, item, index, arr)
    return acc.concat(mapped)
  }, [])
}

console.log([1, 2, 3].flatMap(x => [x, x * 2]));
// [1, 2, 2, 4, 3, 6]
